// Normalize Telegram update → unified shape.
// Handles text messages, voice, photos, and callback_query (inline buttons).

const raw = $input.first().json;
const msg = raw.message || raw.callback_query?.message || {};
const from = raw.message?.from || raw.callback_query?.from || {};
const cb = raw.callback_query;

const userId = String(from.id || '');
const chatId = String(msg.chat?.id || from.id || '');
const username = from.username || '';
const firstName = from.first_name || '';

let type = 'unknown';
let text = '';
if (cb) {
  type = 'callback';
  text = cb.data || '';
} else if (msg.voice) {
  type = 'voice';
  text = '';
} else if (msg.photo) {
  type = 'photo';
  text = msg.caption || '';
} else if (msg.text) {
  type = 'text';
  text = msg.text;
}

return [{ json: {
  userId,
  chatId,
  username,
  firstName,
  type,
  text,
  messageId: msg.message_id || null,
  callbackQueryId: cb?.id || null,
  voiceFileId: msg.voice?.file_id || null,
  photoFileId: msg.photo ? msg.photo[msg.photo.length - 1].file_id : null,
  raw,
} }];

// Merge incoming normalized message + user lookup result.
// If user not found or not active → set authorized=false and stop.
// Else route by intent.

const msg = $('Normalize').first().json;
const users = $input.all().map((i) => i.json);

// Airtable search returns records with fields
const user = users[0]?.fields ? users[0] : (users[0]?.records?.[0]) || null;

if (!user || !user.fields || user.fields.Active !== true) {
  return [{ json: { ...msg, authorized: false, intent: 'unauthorized' } }];
}

const userFields = user.fields;
const text = (msg.text || '').trim();
const lower = text.toLowerCase();

// Naive intent classifier (Phase A — no GPT yet)
let intent = 'unknown';
if (msg.type === 'voice') intent = 'voice_not_supported_yet';
else if (msg.type === 'photo') intent = 'photo_not_supported_yet';
else if (msg.type === 'callback') intent = 'callback_not_supported_yet';
else if (lower === '/start' || lower.startsWith('/start ')) intent = 'start';
else if (lower === '/help' || lower === '/помощь' || lower === 'помощь' || lower === 'что ты умеешь') intent = 'help';
else if (lower === '/график' || lower === '/gantt' || lower.includes('ссылк')) intent = 'gantt';
else if (lower === '/статус' || lower === '/status' || lower === 'статус' || lower === 'как дела') intent = 'status';
else if (lower === '/отмена' || lower === 'отмена' || lower === '/cancel') intent = 'cancel';

return [{ json: { ...msg, authorized: true, userFields, intent } }];
